"use server";

import { redirect } from "next/navigation";
import { setSession, clearSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";

export async function setCurrentUser(formData: FormData) {
  const teamMemberId = formData.get("teamMemberId");
  if (typeof teamMemberId !== "string" || !teamMemberId.trim()) {
    redirect("/?error=missing");
  }

  const member = await prisma.teamMember.findUnique({
    where: { id: teamMemberId.trim() },
  });
  if (!member) {
    redirect("/?error=invalid");
  }

  await setSession(member.id);
  redirect("/");
}

export async function clearCurrentUser() {
  await clearSession();
  redirect("/");
}

/** Stub: set session to first team member and redirect to feed. Use for login UI until real auth exists. */
export async function stubLogin() {
  const first = await prisma.teamMember.findFirst();
  if (!first) redirect("/login?error=no-team");
  await setSession(first.id);
  redirect("/feed");
}
